import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface CampaignData {
  campaign: {
    name: string;
    totalRaised: number;
    goal: number;
    donorCount: number;
  };
  progress: {
    milestone: string;
    amount: number;
  }[];
}

export default function Widget() {
  const data = response.data as CampaignData;
  const { campaign, progress } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              {campaign.name}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Raised: ${campaign.totalRaised.toLocaleString()} of ${campaign.goal.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Donors: {campaign.donorCount}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 140 }}>
            <BarChart
              height={140}
              series={[
                {
                  data: progress.map(p => p.amount),
                  color: '#4CAF50',
                },
              ]}
              xAxis={[
                {
                  data: progress.map(p => p.milestone),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>

          <Stack direction="row" spacing={0.5}>
            {progress.map((p, index) => (
              <Chip
                key={index}
                label={p.milestone}
                sx={{ fontSize: '11px', px: 1, py: 0.5 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
